sql:
SELECT video_title, video_duration, upload_date
FROM videos
ORDER BY upload_date DESC;

SELECT COUNT(session_id) AS total_completed_sessions
FROM encoding_sessions
WHERE status = 'completed';

SELECT video_title, AVG(video_duration) AS average_duration
FROM videos
GROUP BY video_title;

external_knowledge:
- 'marathon runners of the encoding world' refers to encoding profiles with average encoding times significantly longer;
- 'more than 5 minutes' refers to an average encoding duration greater than 300 seconds;
- 'voyages' metaphorically represents the encoding sessions.
